mapper.select:
SELECT a.*, p.code AS "projectCode", p.name AS "projectName",
       s.stage_name AS "stageName", u.name AS "filledByName"
FROM construction_log a
LEFT JOIN project p ON p.id = a.project_id
LEFT JOIN project_stage s ON s.id = a.stage_id
LEFT JOIN sys_account u ON u.id = a.filled_by



            AND p.name LIKE CONCAT('%', #{params.projectName}, '%')
            AND p.name LIKE '%' || #{params.projectName} || '%'


    AND a.log_type = #{params.logType}
    AND a.status = #{params.status}
    AND a.log_date >= #{params.startDate}
    AND a.log_date <= #{params.endDate}

ORDER BY a.log_date DESC, a.id DESC
